WITH Ranked AS (
  SELECT id, code, coins_needed, power,
         ROW_NUMBER() OVER(____ BY code, power ____ BY coins_needed ____) AS rn
  FROM staging.wands
)
SELECT * FROM Ranked WHERE rn = ____;

SELECT user_id, session_start,
  ____(session_start) OVER(PARTITION BY user_id ORDER BY session_start) AS prev_session
FROM core.user_sessions;

WITH RankedData AS (
  SELECT *,
         ROW_NUMBER() OVER(PARTITION BY ____ ORDER BY ____ DESC) AS rn
  FROM staging.users
)
SELECT * FROM RankedData WHERE rn = ____;
